import { createSlice, createSelector } from "@reduxjs/toolkit";

const initialState = {
  items: [], // [{ dish_id, res_id, dish_link, quantity }]
};

const cartSlice = createSlice({
  name: "cart",
  initialState,
  reducers: {
    /**
     * Add an item to the cart.
     * If (dish_id + res_id) already exists, increments quantity by 1.
     * payload: { dish_id, res_id, dish_link }
     */
    addToCart: (state, action) => {
      const { dish_id, res_id, dish_link } = action.payload;
      const existing = state.items.find(
        (i) => String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id)
      );
      if (existing) {
        existing.quantity += 1;
      } else {
        state.items.push({ dish_id, res_id, dish_link, quantity: 1 });
      }
    },

    /**
     * Remove one unit of an item.
     * If quantity reaches 0, the item is dropped from the list entirely.
     * payload: { dish_id, res_id }
     */
    removeFromCart: (state, action) => {
      const { dish_id, res_id } = action.payload;
      const idx = state.items.findIndex(
        (i) => String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id)
      );
      if (idx === -1) return;
      if (state.items[idx].quantity > 1) {
        state.items[idx].quantity -= 1;
      } else {
        state.items.splice(idx, 1);
      }
    },

    /**
     * Completely remove a line item regardless of quantity.
     * payload: { dish_id, res_id }
     */
    dropFromCart: (state, action) => {
      const { dish_id, res_id } = action.payload;
      state.items = state.items.filter(
        (i) => !(String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id))
      );
    },

    /**
     * Set an explicit quantity for a line item.
     * If quantity <= 0, drops the item.
     * payload: { dish_id, res_id, quantity }
     */
    setQuantity: (state, action) => {
      const { dish_id, res_id, quantity } = action.payload;
      const idx = state.items.findIndex(
        (i) => String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id)
      );
      if (idx === -1) return;
      if (quantity <= 0) {
        state.items.splice(idx, 1);
      } else {
        state.items[idx].quantity = quantity;
      }
    },

    /** Wipe the entire cart. */
    clearCart: () => initialState,

    /**
     * Sync cart from the server-side session (used by the polling response).
     * payload: cart array from backend  OR  null
     */
    syncCartFromServer: (state, action) => {
      if (!action.payload) return;
      // Backend sends raw 3-tuples — normalise by adding quantity: 1 if missing
      state.items = action.payload.map((item) => ({
        dish_id:   item.dish_id,
        res_id:    item.res_id,
        dish_link: item.dish_link,
        quantity:  item.quantity ?? 1,
      }));
    },
  },
});

export const {
  addToCart,
  removeFromCart,
  dropFromCart,
  setQuantity,
  clearCart,
  syncCartFromServer,
} = cartSlice.actions;

export default cartSlice.reducer;


// ─────────────────────────────────────────────────────────────────
// Selectors
// ─────────────────────────────────────────────────────────────────

/** Raw items array */
export const selectCartItems = (state) => state.cart.items;

/** Total number of distinct line items */
export const selectCartLineCount = (state) => state.cart.items.length;

/** Total units across all lines (shown on cart badge) */
export const selectCartTotalUnits = createSelector(
  selectCartItems,
  (items) => items.reduce((sum, i) => sum + i.quantity, 0)
);

/** True if the cart has at least one item */
export const selectCartHasItems = createSelector(
  selectCartItems,
  (items) => items.length > 0
);

/**
 * Quantity for a specific (dish_id, res_id) pair.
 * Returns 0 if not in cart.
 * Usage: useSelector(selectItemQuantity(dish_id, res_id))
 */
export const selectItemQuantity = (dish_id, res_id) => (state) => {
  const item = state.cart.items.find(
    (i) => String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id)
  );
  return item?.quantity ?? 0;
};

/**
 * True if a specific (dish_id, res_id) is in the cart.
 * Usage: useSelector(selectIsInCart(dish_id, res_id))
 */
export const selectIsInCart = (dish_id, res_id) => (state) =>
  state.cart.items.some(
    (i) => String(i.dish_id) === String(dish_id) && String(i.res_id) === String(res_id)
  );

/**
 * All cart items that belong to a specific restaurant.
 * Useful for per-restaurant cart summaries.
 * Usage: useSelector(selectCartItemsByRes(res_id))
 */
export const selectCartItemsByRes = (res_id) =>
  createSelector(selectCartItems, (items) =>
    items.filter((i) => String(i.res_id) === String(res_id))
  );
